    if (!isVisitingWithLocalePath) {
      req.nextUrl.locale = newLocale;
      req.nextUrl.pathname = `/${newLocale}`;
    } else {
      req.nextUrl.locale =
        currentPathName === `/${country}`
          ? DEFAULT_LOCALE
          : currentPathName.split("/")[1];
    }

    return NextResponse.rewrite(req.nextUrl).cookie("NEXT_LOCALE", newLocale);
