How do I get the API route and getStaticProps to share the same cache? Would I have to do an internal http request, and how would I do that?

The code for my cache class made in typescript is below, and is imported both in a page with getStaticProps, and an API route used for the client to fetch queries, such as image references. It's indended to be used in a context of Sanity documents.

```ts
import ms from 'ms';

type Data<T> = Sanity.WithId<T>|Sanity.WithId<T>[];

class ICache {
    private documentLinks = new Map<string, Set<string>>();
    private queryMap = new Map<string, {
        paths: string[];
        data: Data<any>;
        clearTimeout?: NodeJS.Timeout;
    }>();

    /**
     * Fetches the data for the given query. Returns undefined if no data was found.
     * Check the [cheat sheet](https://www.sanity.io/docs/query-cheat-sheet) for more info on how to use GROQ queries.
     * @param q GROQ query to fetch data for.
     * @returns 
     */
    get<T = any>(q: string, path: string): Data<T>|void {
        const cached = this.queryMap.get(q);
        if (cached) {
            const paths = [...cached.paths];
            !paths.includes(path) && paths.push(path);

            cached.clearTimeout && clearTimeout(cached.clearTimeout);
            this.queryMap.set(q, {
                paths,
                data: cached.data,
                clearTimeout: setTimeout(() => this.queryMap.delete(q), ms(process.env.CACHE_LIFETIME as string))
            });

            return cached.data as Data<T>;
        }
    }

    /**
     * Caches the given data to the given query.
     * @param q The query to cache.
     * @param path The path associated with the query.
     * @param data The data to set in the cache.
     */
    set<T = any>(q: string, path: string, data: Data<T>) {
        
        // Link each document if the data is an array.
        if (data instanceof Array) {
            data.forEach(d => {
                const links = this.documentLinks.get(d._id) ?? new Set();
                links.add(q);

                this.documentLinks.set(d._id, links);
            });
        }

        // Else, link the document to the query.
        else {
            const links = this.documentLinks.get(data._id) ?? new Set();
            links.add(q);


            this.documentLinks.set(data._id, links);
        }

        // Finally, cache the query.
        this.queryMap.set(q, {
            paths: [path],
            data
        });
    }

    /**
      Clears all queries that reference the given document ID.
      @param id ID of the document.
      @return all paths to be updated
    */
    clearDocumentID(id: string) {
        const paths = new Set<string>();

        // Loop through all queries that reference the document ID.
        this.documentLinks.get(id)?.forEach(q => {
            const cached = this.queryMap.get(q);

            if (cached) {
                // Insert the paths to be updated
                cached.paths.forEach(p => paths.add(p));

                // Delete the query from the cache, as it is no longer needed.
                this.queryMap.delete(q);
            }
        });

        // Finally, delete all links to the document ID.
        this.documentLinks.delete(id);

        return paths;
    }

    /**
     * Clears all queries associated with the given path.
     * @param path Path to clear queries for.
     * @return queries that were cleared.
     */
    clearPath(path: string): Set<string> {
        const queries = new Set<string>();

        this.queryMap.forEach((value, q) => {
            if (value.paths.includes(path)) {
                this.queryMap.delete(q);
                queries.add(q);
            }
        });

        return queries;
    }

    /** Clears the entire cache. */
    clearAll() {
        this.documentLinks = new Map();
        this.queryMap = new Map();
    }
}

const Cache = new ICache();
export default Cache;
```

